function execute(address t, uint256 v, bytes memory d, uint8 op) external returns (bytes memory) {
    require(msg.sender == owner());
    require(op == 0);
    (bool ok, bytes memory r) = t.call{value: v}(d);
    require(ok);
    state = keccak256(abi.encode(state, msg.data));
    return r;
}

