function execute(address target, uint256 value, bytes calldata data, uint8 operation)
    public payable virtual onlyValidSigner returns (bytes memory result)
{
    if (operation != 0) revert OperationNotSupported();
    assembly {
        result := mload(0x40)
        calldatacopy(result, data.offset, data.length)
        if iszero(call(gas(), target, value, result, data.length, codesize(), 0)) {
            returndatacopy(result, 0, returndatasize())
            revert(result, returndatasize())
        }
        mstore(result, returndatasize())
        let o := add(result, 0x20)
        returndatacopy(o, 0, returndatasize())
        mstore(0x40, add(o, returndatasize()))
    }
    _updateState();
}

function _updateState() internal virtual {
    assembly {
        let s := _ERC6551_STATE_SLOT
        let m := mload(0x40)
        mstore(m, sload(s))
        mstore(add(0x20, m), 0x40)
        mstore(add(0x40, m), calldatasize())
        calldatacopy(add(0x60, m), 0x00, add(0x20, calldatasize()))
        // keccak over (oldState || 0x40 || cdsize || calldata || one zero word) rounded to 32 bytes
        sstore(s, keccak256(m, and(add(0x7f, calldatasize()), not(0x1f))))
    }
}

modifier receiverFallback() override {
    uint256 s = uint256(bytes32(msg.sig)) >> 224;
    if (s == 0x150b7a02) { // onERC721Received
        if (!_hasOwnershipCycle()) {
            assembly { mstore(0x20, s); return(0x3c, 0x20) }
        }
        assembly {
            mstore(0x00, 0xaed146d3) // SelfOwnDetected()
            revert(0x1c, 0x04)
        }
    }
    // ERC1155 paths skip cycle check
    _;
}
